-- ===================================================================
-- COURSE: Form Design and Development
-- ===================================================================
VALUES (UUID(), 17, 1, TRUE, 1, NOW(), FALSE);
SET @course_id = LAST_INSERT_ID();



-- ===================================================================
-- LESSON 1: Form Basics & Structure
-- ===================================================================
VALUES (UUID(), '[{"type":"heading","content":{"en":"Form Basics & Structure","fr":"Bases et structure des formulaires"},"properties":{"level":1}},{"type":"paragraph","content":{"en":"Forms are structured data entry interfaces that allow healthcare workers to capture patient information consistently and efficiently. In OpenMRS, forms are the primary tool for recording clinical data during patient encounters. Understanding how forms are structured and their connection to the Concept Dictionary is essential for building effective data collection tools.","fr":"Les formulaires sont des interfaces de saisie de données structurées qui permettent aux professionnels de santé de capturer les informations des patients de manière cohérente et efficace. Dans OpenMRS, les formulaires sont l''outil principal pour enregistrer des données cliniques pendant les rencontres avec les patients. Comprendre comment les formulaires sont structurés et leur connexion au Dictionnaire de concepts est essentiel pour construire des outils de collecte de données efficaces."}},{"type":"heading","content":{"en":"Common Form Use Cases","fr":"Cas d''utilisation courants des formulaires"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"Forms serve many purposes in healthcare settings. Understanding these use cases helps you design forms that meet clinical needs:","fr":"Les formulaires servent de nombreux objectifs dans les établissements de santé. Comprendre ces cas d''utilisation vous aide à concevoir des formulaires qui répondent aux besoins cliniques :"}},{"type":"list","items":[{"en":"Vital Signs: Record basic measurements like weight, height, temperature, blood pressure, and pulse during patient visits","fr":"Signes vitaux : Enregistrer les mesures de base comme le poids, la taille, la température, la pression artérielle et le pouls lors des visites de patients"},{"en":"Clinical Encounters: Document patient complaints, examinations, diagnoses, and treatment plans during consultations","fr":"Rencontres cliniques : Documenter les plaintes des patients, les examens, les diagnostics et les plans de traitement pendant les consultations"},{"en":"Medical History: Collect information about past illnesses, surgeries, allergies, and family medical history","fr":"Antécédents médicaux : Collecter des informations sur les maladies passées, les chirurgies, les allergies et les antécédents médicaux familiaux"},{"en":"Lab Orders and Results: Request laboratory tests and record results when they become available","fr":"Ordres et résultats de laboratoire : Demander des tests de laboratoire et enregistrer les résultats lorsqu''ils sont disponibles"}],"properties":{"ordered":false}},{"type":"heading","content":{"en":"Form Structure Hierarchy","fr":"Hiérarchie de structure de formulaire"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"OpenMRS forms follow a three-level hierarchy that organizes questions logically. Understanding this structure is crucial for building user-friendly forms:","fr":"Les formulaires OpenMRS suivent une hiérarchie à trois niveaux qui organise les questions de manière logique. Comprendre cette structure est crucial pour construire des formulaires conviviaux :"}},{"type":"list","items":[{"en":"Pages: The top level that divides the form into major sections. Use pages for distinct phases of data collection or when forms are very long. Each page is displayed separately during data entry.","fr":"Pages : Le niveau supérieur qui divise le formulaire en sections principales. Utilisez des pages pour des phases distinctes de collecte de données ou lorsque les formulaires sont très longs. Chaque page s''affiche séparément pendant la saisie de données."},{"en":"Sections: Subdivisions within a page that group related questions together. Sections typically have headers and can be collapsed/expanded. Use sections to organize questions by topic or clinical area.","fr":"Sections : Subdivisions au sein d''une page qui regroupent des questions connexes. Les sections ont généralement des en-têtes et peuvent être réduites/développées. Utilisez des sections pour organiser les questions par sujet ou domaine clinique."},{"en":"Questions: Individual data fields that collect specific pieces of information. Each question is linked to a concept from the dictionary, which determines what type of data can be entered.","fr":"Questions : Champs de données individuels qui collectent des informations spécifiques. Chaque question est liée à un concept du dictionnaire, qui détermine le type de données pouvant être saisi."}],"properties":{"ordered":true}},{"type":"paragraph","content":{"en":"This hierarchical structure keeps forms organized and easy to navigate. A typical vital signs form might have one page with two sections: Basic Vitals (weight, height, temperature) and Blood Pressure (systolic and diastolic). Each measurement is a question linked to its corresponding concept.","fr":"Cette structure hiérarchique garde les formulaires organisés et faciles à naviguer. Un formulaire typique de signes vitaux pourrait avoir une page avec deux sections : Signes vitaux de base (poids, taille, température) et Pression artérielle (systolique et diastolique). Chaque mesure est une question liée à son concept correspondant."}},{"type":"heading","content":{"en":"Connection to the Concept Dictionary","fr":"Connexion au Dictionnaire de concepts"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"The most important aspect of OpenMRS forms is their connection to the Concept Dictionary. Every question in a form must be linked to a concept that defines what data is being collected. This linkage ensures data standardization and enables reporting. When you create a question asking for patient weight, you link it to the Weight concept from the dictionary. That concept defines that weight is a numeric value measured in kilograms, has validation ranges, and may have mappings to international standards.","fr":"L''aspect le plus important des formulaires OpenMRS est leur connexion au Dictionnaire de concepts. Chaque question dans un formulaire doit être liée à un concept qui définit quelles données sont collectées. Cette liaison garantit la standardisation des données et permet des rapports. Lorsque vous créez une question demandant le poids du patient, vous la liez au concept de Poids du dictionnaire. Ce concept définit que le poids est une valeur numérique mesurée en kilogrammes, a des plages de validation et peut avoir des mappages vers des normes internationales."}},{"type":"paragraph","content":{"en":"This concept-based approach has major benefits. First, data from different forms that use the same concept is automatically comparable - a Weight value captured in an admission form can be directly compared with one from a follow-up visit form. Second, you do not need to redefine data types, units, or validation rules for each question - the concept carries that information. Third, when concepts have mappings to international standards, your form data automatically becomes interoperable with external systems.","fr":"Cette approche basée sur les concepts présente des avantages majeurs. Premièrement, les données de différents formulaires qui utilisent le même concept sont automatiquement comparables - une valeur de Poids capturée dans un formulaire d''admission peut être directement comparée avec une provenant d''un formulaire de visite de suivi. Deuxièmement, vous n''avez pas besoin de redéfinir les types de données, les unités ou les règles de validation pour chaque question - le concept contient ces informations. Troisièmement, lorsque les concepts ont des mappages vers des normes internationales, vos données de formulaire deviennent automatiquement interopérables avec des systèmes externes."}},{"type":"alert","content":{"en":"Important: Before creating forms, ensure you have created the necessary concepts in the Concept Dictionary. You cannot build form questions without concepts to link them to. Plan your concept dictionary first, then build your forms.","fr":"Important : Avant de créer des formulaires, assurez-vous d''avoir créé les concepts nécessaires dans le Dictionnaire de concepts. Vous ne pouvez pas construire de questions de formulaire sans concepts auxquels les lier. Planifiez d''abord votre dictionnaire de concepts, puis construisez vos formulaires."},"properties":{"variant":"warning"}},{"type":"heading","content":{"en":"Accessing Form Management","fr":"Accéder à la gestion des formulaires"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"To manage forms in OpenMRS 3, navigate to the App Menu (top right) → System Administration → Legacy Admin. From there, you can access form management tools to create new forms, edit existing ones, and configure form properties. To fill out forms for patients, use Fast Data Entry from the App Menu, which provides a streamlined interface for clinical data entry.","fr":"Pour gérer les formulaires dans OpenMRS 3, naviguez vers le Menu d''applications (en haut à droite) → Administration système → Administration héritée. De là, vous pouvez accéder aux outils de gestion des formulaires pour créer de nouveaux formulaires, modifier les existants et configurer les propriétés des formulaires. Pour remplir des formulaires pour les patients, utilisez Saisie rapide de données depuis le Menu d''applications, qui fournit une interface rationalisée pour la saisie de données cliniques."}}]', 3, 1, NOW(), FALSE);
SET @lesson_id_1 = LAST_INSERT_ID();



-- ===================================================================
-- EXERCISE 1: Form Use Cases (Multiple Choice)
-- ===================================================================
VALUES (UUID(), 'MULTIPLE_CHOICE', '{"question":{"en":"Which of the following is the PRIMARY benefit of linking every form question to a concept from the Concept Dictionary?","fr":"Lequel des éléments suivants est l''avantage PRINCIPAL de lier chaque question de formulaire à un concept du Dictionnaire de concepts ?"},"options":[{"id":"a","text":{"en":"It makes forms visually more attractive","fr":"Cela rend les formulaires visuellement plus attrayants"}},{"id":"b","text":{"en":"It ensures data standardization and enables consistent reporting across different forms","fr":"Cela garantit la standardisation des données et permet des rapports cohérents sur différents formulaires"}},{"id":"c","text":{"en":"It automatically translates forms into multiple languages","fr":"Cela traduit automatiquement les formulaires dans plusieurs langues"}},{"id":"d","text":{"en":"It reduces the file size of form definitions","fr":"Cela réduit la taille de fichier des définitions de formulaire"}}],"hint":{"en":"Think about why OpenMRS uses concepts rather than letting each form define its own questions independently.","fr":"Pensez à pourquoi OpenMRS utilise des concepts plutôt que de laisser chaque formulaire définir ses propres questions indépendamment."}}', '{"correctAnswer":"b"}', '{"correct":{"en":"Correct! The primary benefit of linking questions to concepts is data standardization. When multiple forms use the same Weight concept, all weight data across your system is collected with the same units, validation rules, and structure. This makes data comparable and enables meaningful reports. The concept also carries international mappings, making your data interoperable. This is why the Concept Dictionary is so fundamental to OpenMRS - it ensures that everyone in your organization records information the same way.","fr":"Correct ! L''avantage principal de lier les questions aux concepts est la standardisation des données. Lorsque plusieurs formulaires utilisent le même concept de Poids, toutes les données de poids de votre système sont collectées avec les mêmes unités, règles de validation et structure. Cela rend les données comparables et permet des rapports significatifs. Le concept contient également des mappages internationaux, rendant vos données interopérables. C''est pourquoi le Dictionnaire de concepts est si fondamental pour OpenMRS - il garantit que tout le monde dans votre organisation enregistre les informations de la même manière."},"incorrect":{"en":"Not quite. Review the Connection to the Concept Dictionary section. The key benefit is data standardization - when different forms use the same concepts, the data they collect is automatically consistent and comparable. This enables reporting and analysis across your entire system.","fr":"Pas tout à fait. Révisez la section Connexion au Dictionnaire de concepts. L''avantage clé est la standardisation des données - lorsque différents formulaires utilisent les mêmes concepts, les données qu''ils collectent sont automatiquement cohérentes et comparables. Cela permet des rapports et analyses dans tout votre système."}}', TRUE, 1, NOW(), FALSE);
SET @exercise_id_1 = LAST_INSERT_ID();


-- ===================================================================
-- EXERCISE 2: Form Structure (Matching)
-- ===================================================================
VALUES (UUID(), 'MATCHING', '{"instructions":{"en":"Match each level of the form structure hierarchy with its appropriate description and use case.","fr":"Associez chaque niveau de la hiérarchie de structure de formulaire à sa description et son cas d''utilisation appropriés."},"leftItems":[{"id":"1","text":{"en":"Pages","fr":"Pages"}},{"id":"2","text":{"en":"Sections","fr":"Sections"}},{"id":"3","text":{"en":"Questions","fr":"Questions"}}],"rightItems":[{"id":"a","text":{"en":"Individual data fields linked to concepts that collect specific information","fr":"Champs de données individuels liés à des concepts qui collectent des informations spécifiques"}},{"id":"b","text":{"en":"Top-level divisions for distinct phases of data collection, displayed separately","fr":"Divisions de niveau supérieur pour des phases distinctes de collecte de données, affichées séparément"}},{"id":"c","text":{"en":"Subdivisions that group related questions by topic, with collapsible headers","fr":"Subdivisions qui regroupent des questions connexes par sujet, avec des en-têtes réductibles"}}]}', '{"correctMatches":{"1":"b","2":"c","3":"a"}}', '{"correct":{"en":"Excellent! You understand the three-level form structure. Pages are the highest level for major divisions, Sections organize questions within pages by topic, and Questions are the actual data fields. This hierarchy helps keep forms organized and user-friendly. When designing forms, think about how to break complex data collection into logical pages and sections, making it easier for clinicians to navigate and ensuring related information is grouped together.","fr":"Excellent ! Vous comprenez la structure de formulaire à trois niveaux. Les Pages sont le niveau le plus élevé pour les divisions principales, les Sections organisent les questions au sein des pages par sujet, et les Questions sont les champs de données réels. Cette hiérarchie aide à garder les formulaires organisés et conviviaux. Lors de la conception de formulaires, pensez à comment diviser la collecte de données complexes en pages et sections logiques, facilitant la navigation pour les cliniciens et garantissant que les informations connexes sont regroupées."}},"incorrect":{"en":"Review the Form Structure Hierarchy section. Remember the three levels from top to bottom: Pages (major divisions, separate displays), Sections (topical groupings within pages), and Questions (individual data fields linked to concepts). Think about how you would organize a multi-part form logically.","fr":"Révisez la section Hiérarchie de structure de formulaire. Rappelez-vous les trois niveaux du haut vers le bas : Pages (divisions principales, affichages séparés), Sections (regroupements thématiques au sein des pages), et Questions (champs de données individuels liés aux concepts). Pensez à comment vous organiseriez logiquement un formulaire en plusieurs parties."}}', TRUE, 1, NOW(), FALSE);
SET @exercise_id_2 = LAST_INSERT_ID();


-- ===================================================================
-- LESSON 2: Linking Questions to Concepts
-- ===================================================================
VALUES (UUID(), '[{"type":"heading","content":{"en":"Linking Questions to Concepts","fr":"Lier des questions aux concepts"},"properties":{"level":1}},{"type":"paragraph","content":{"en":"The process of linking form questions to concepts is what transforms a simple form into a standardized data collection tool. This connection determines what type of data the question accepts, how it is validated, and how it appears in reports. Understanding this linking process is essential for creating effective forms.","fr":"Le processus de liaison des questions de formulaire aux concepts est ce qui transforme un formulaire simple en un outil de collecte de données standardisé. Cette connexion détermine le type de données que la question accepte, comment elle est validée et comment elle apparaît dans les rapports. Comprendre ce processus de liaison est essentiel pour créer des formulaires efficaces."}},{"type":"heading","content":{"en":"How Concept Linking Works","fr":"Comment fonctionne la liaison de concepts"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"When you create a question in a form, you must specify which concept from the dictionary that question represents. The concept you choose determines several critical aspects of the question:","fr":"Lorsque vous créez une question dans un formulaire, vous devez spécifier quel concept du dictionnaire cette question représente. Le concept que vous choisissez détermine plusieurs aspects critiques de la question :"}},{"type":"list","items":[{"en":"Data Type: The concept''s datatype constrains available rendering options. Numeric concepts use number inputs, coded concepts can use dropdowns, radio buttons, or checkboxes, and text concepts use text inputs.","fr":"Type de données : Le type de données du concept limite les options de rendu disponibles. Les concepts numériques utilisent des champs numériques, les concepts codés peuvent utiliser des menus déroulants, des boutons radio ou des cases à cocher, et les concepts texte utilisent des champs de texte."},{"en":"Validation Rules: Numeric concepts enforce their ranges, coded concepts only accept their defined answers, and all types validate according to their concept configuration.","fr":"Règles de validation : Les concepts numériques appliquent leurs plages, les concepts codés n''acceptent que leurs réponses définies, et tous les types valident selon leur configuration de concept."},{"en":"Display Properties: Question labels are specified in the form definition, while the concept defines the underlying data structure.","fr":"Propriétés d''affichage : Les étiquettes des questions sont spécifiées dans la définition du formulaire, tandis que le concept définit la structure de données sous-jacente."},{"en":"Data Storage: All data collected through this question is stored as observations of that concept, enabling reporting and analysis.","fr":"Stockage des données : Toutes les données collectées via cette question sont stockées comme observations de ce concept, permettant les rapports et l''analyse."}],"properties":{"ordered":false}},{"type":"heading","content":{"en":"Choosing the Right Concept","fr":"Choisir le bon concept"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"Selecting the appropriate concept for each question is crucial. Use existing concepts from your dictionary whenever possible - this ensures consistency across forms. If you are creating a weight question, search for \\"Weight\\" in the concept dictionary and use the existing Weight concept rather than creating a new one. This way, weight data from all forms will be comparable.","fr":"Sélectionner le concept approprié pour chaque question est crucial. Utilisez les concepts existants de votre dictionnaire autant que possible - cela garantit la cohérence entre les formulaires. Si vous créez une question de poids, recherchez \\"Poids\\" dans le dictionnaire de concepts et utilisez le concept de Poids existant plutôt que d''en créer un nouveau. De cette façon, les données de poids de tous les formulaires seront comparables."}},{"type":"paragraph","content":{"en":"Only create new concepts when you truly need to capture information that is not covered by existing concepts. Before creating a new concept, search thoroughly using synonyms and alternate terminology. For common clinical measurements, check the CIEL dictionary to see if a standardized concept already exists with proper mappings.","fr":"Ne créez de nouveaux concepts que lorsque vous devez vraiment capturer des informations qui ne sont pas couvertes par les concepts existants. Avant de créer un nouveau concept, recherchez minutieusement en utilisant des synonymes et une terminologie alternative. Pour les mesures cliniques courantes, vérifiez le dictionnaire CIEL pour voir si un concept standardisé existe déjà avec des mappages appropriés."}},{"type":"heading","content":{"en":"Concept Sets in Forms","fr":"Ensembles de concepts dans les formulaires"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"Concept sets can be used to group related questions together in forms. For example, a Blood Pressure concept set keeps systolic and diastolic measurements visually organized as a logical unit.","fr":"Les ensembles de concepts peuvent être utilisés pour regrouper des questions connexes dans les formulaires. Par exemple, un ensemble de concepts de Pression artérielle garde les mesures systolique et diastolique visuellement organisées comme une unité logique."}},{"type":"paragraph","content":{"en":"Using concept sets in forms helps organize related measurements and ensures they are collected together, improving data quality and making forms easier to navigate.","fr":"L''utilisation d''ensembles de concepts dans les formulaires aide à organiser les mesures connexes et garantit qu''elles sont collectées ensemble, améliorant la qualité des données et facilitant la navigation dans les formulaires."}},{"type":"alert","content":{"en":"Best Practice: Before starting form development, create all necessary concepts in the dictionary. Then search for and reuse existing concepts when building questions. This concept-first approach ensures data consistency and reduces duplication across your forms.","fr":"Meilleure pratique : Avant de commencer le développement de formulaires, créez tous les concepts nécessaires dans le dictionnaire. Ensuite, recherchez et réutilisez les concepts existants lors de la construction de questions. Cette approche concept d''abord garantit la cohérence des données et réduit la duplication dans vos formulaires."},"properties":{"variant":"success"}}]', 2, 1, NOW(), FALSE);
SET @lesson_id_2 = LAST_INSERT_ID();



-- ===================================================================
-- LESSON 3: Building & Publishing Forms
-- ===================================================================
VALUES (UUID(), '[{"type":"heading","content":{"en":"Building & Publishing Forms","fr":"Construire et publier des formulaires"},"properties":{"level":1}},{"type":"paragraph","content":{"en":"Once you understand form structure and concept linking, you are ready to build and deploy forms. This lesson covers the essential field types, validation rules, testing procedures, and the publishing workflow that takes forms from development to production use.","fr":"Une fois que vous comprenez la structure de formulaire et la liaison de concepts, vous êtes prêt à construire et déployer des formulaires. Cette leçon couvre les types de champs essentiels, les règles de validation, les procédures de test et le flux de publication qui fait passer les formulaires du développement à l''utilisation en production."}},{"type":"heading","content":{"en":"Essential Field Types","fr":"Types de champs essentiels"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"OpenMRS supports several field types that correspond to concept datatypes. Understanding when to use each type is important for building user-friendly forms:","fr":"OpenMRS prend en charge plusieurs types de champs qui correspondent aux types de données de concept. Comprendre quand utiliser chaque type est important pour construire des formulaires conviviaux :"}},{"type":"list","items":[{"en":"Numeric: For measurements with units (weight, temperature, lab values). Automatically validates against absolute ranges defined in the concept.","fr":"Numérique : Pour les mesures avec unités (poids, température, valeurs de laboratoire). Valide automatiquement contre les plages absolues définies dans le concept."},{"en":"Coded: For multiple choice questions (blood type, diagnosis). Can be rendered as dropdown menus, radio buttons, or checkboxes as specified in the form definition. Only accepts predefined answers.","fr":"Codé : Pour les questions à choix multiples (groupe sanguin, diagnostic). Peut être rendu sous forme de menus déroulants, de boutons radio ou de cases à cocher selon la définition du formulaire. N''accepte que les réponses prédéfinies."},{"en":"Text: For free-text entry (patient complaints, clinical notes). Allows flexible input but reduces data standardization. Use sparingly.","fr":"Texte : Pour la saisie de texte libre (plaintes de patients, notes cliniques). Permet une saisie flexible mais réduit la standardisation des données. À utiliser avec parcimonie."},{"en":"Date: For dates (visit date, date of birth). Provides calendar picker for easy selection and validates date formats.","fr":"Date : Pour les dates (date de visite, date de naissance). Fournit un sélecteur de calendrier pour une sélection facile et valide les formats de date."},{"en":"Boolean: For yes/no questions (pregnant?, smoker?). Can be rendered as checkboxes or toggle switches.","fr":"Booléen : Pour les questions oui/non (enceinte ?, fumeur ?). Peut être rendu sous forme de cases à cocher ou de commutateurs."}],"properties":{"ordered":false}},{"type":"heading","content":{"en":"Validation Rules","fr":"Règles de validation"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"Validation rules help ensure data quality by preventing invalid entries. The most important validations are inherited automatically from concepts - numeric ranges, coded answer sets, and data type constraints. You can also add form-level validations:","fr":"Les règles de validation aident à garantir la qualité des données en empêchant les saisies invalides. Les validations les plus importantes sont héritées automatiquement des concepts - plages numériques, ensembles de réponses codées et contraintes de type de données. Vous pouvez également ajouter des validations au niveau du formulaire :"}},{"type":"list","items":[{"en":"Required Fields: Mark critical questions as required to ensure essential data is collected. Required fields cannot be left blank.","fr":"Champs requis : Marquez les questions critiques comme requises pour garantir que les données essentielles sont collectées. Les champs requis ne peuvent pas être laissés vides."},{"en":"Conditional Logic: Show or hide questions based on previous answers. Example: Only show pregnancy-related questions if gender is female.","fr":"Logique conditionnelle : Afficher ou masquer des questions en fonction des réponses précédentes. Exemple : N''afficher les questions liées à la grossesse que si le sexe est féminin."},{"en":"Range Warnings: Alert users when values fall outside normal ranges while still allowing entry for legitimate abnormal values.","fr":"Avertissements de plage : Alerter les utilisateurs lorsque les valeurs sortent des plages normales tout en permettant la saisie pour des valeurs anormales légitimes."}],"properties":{"ordered":false}},{"type":"heading","content":{"en":"Testing Your Form","fr":"Tester votre formulaire"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"Always test forms thoroughly in a development environment before publishing to production. Testing should include:","fr":"Testez toujours minutieusement les formulaires dans un environnement de développement avant de publier en production. Les tests devraient inclure :"}},{"type":"list","items":[{"en":"Complete the form as a clinician would, testing all question types and validation rules","fr":"Remplir le formulaire comme le ferait un clinicien, en testant tous les types de questions et règles de validation"},{"en":"Try to enter invalid data to verify that validations work correctly","fr":"Essayer de saisir des données invalides pour vérifier que les validations fonctionnent correctement"},{"en":"Submit the form and verify that data appears correctly in the patient chart and database","fr":"Soumettre le formulaire et vérifier que les données apparaissent correctement dans le dossier patient et la base de données"},{"en":"Test with different user roles to ensure permissions work as expected","fr":"Tester avec différents rôles d''utilisateur pour garantir que les autorisations fonctionnent comme prévu"}],"properties":{"ordered":true}},{"type":"alert","content":{"en":"Critical: Never skip testing, even for simple forms. A small error in a widely-used form can corrupt thousands of patient records and require extensive data cleanup. Always test in development before publishing to production.","fr":"Critique : Ne sautez jamais les tests, même pour les formulaires simples. Une petite erreur dans un formulaire largement utilisé peut corrompre des milliers de dossiers de patients et nécessiter un nettoyage de données extensif. Testez toujours en développement avant de publier en production."},"properties":{"variant":"warning"}},{"type":"heading","content":{"en":"Publishing Workflow","fr":"Flux de publication"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"Once testing is complete, follow this workflow to publish your form to production:","fr":"Une fois les tests terminés, suivez ce flux de travail pour publier votre formulaire en production :"}},{"type":"list","items":[{"en":"Review all questions, validations, and structure one final time","fr":"Révisez toutes les questions, validations et structure une dernière fois"},{"en":"Set the form as Published in the form properties to make it available to users","fr":"Définissez le formulaire comme Publié dans les propriétés du formulaire pour le rendre disponible aux utilisateurs"},{"en":"Configure which encounter types the form is associated with","fr":"Configurez les types de rencontres auxquels le formulaire est associé"},{"en":"Set appropriate user permissions to control who can use the form","fr":"Définissez des autorisations utilisateur appropriées pour contrôler qui peut utiliser le formulaire"},{"en":"Train staff on the new form before widespread deployment","fr":"Formez le personnel sur le nouveau formulaire avant un déploiement généralisé"},{"en":"Monitor initial usage closely and be ready to make adjustments based on user feedback","fr":"Surveillez de près l''utilisation initiale et soyez prêt à faire des ajustements basés sur les retours des utilisateurs"}],"properties":{"ordered":true}},{"type":"paragraph","content":{"en":"After publishing, you can create new versions of forms as needs change. OpenMRS maintains version history, allowing you to update forms while preserving data collected with previous versions. This versioning system ensures that historical data remains valid even as your forms evolve.","fr":"Après publication, vous pouvez créer de nouvelles versions de formulaires à mesure que les besoins changent. OpenMRS maintient un historique de versions, vous permettant de mettre à jour les formulaires tout en préservant les données collectées avec les versions précédentes. Ce système de versionnement garantit que les données historiques restent valides même lorsque vos formulaires évoluent."}},{"type":"alert","content":{"en":"Tip: Start with simple forms and gradually add complexity. It is better to deploy a basic working form quickly and iterate based on user feedback than to spend weeks building a complex form that may not meet actual user needs.","fr":"Conseil : Commencez avec des formulaires simples et ajoutez progressivement de la complexité. Il est préférable de déployer rapidement un formulaire de base fonctionnel et d''itérer en fonction des retours utilisateurs que de passer des semaines à construire un formulaire complexe qui pourrait ne pas répondre aux besoins réels des utilisateurs."},"properties":{"variant":"info"}}]', 2, 1, NOW(), FALSE);
SET @lesson_id_3 = LAST_INSERT_ID();



-- ===================================================================
-- EXERCISE 3: Matching - Field Types and Use Cases
-- ===================================================================
VALUES (UUID(), 'MATCHING', '{"instructions":{"en":"Match each concept datatype with the clinical use case it best fits.","fr":"Associez chaque type de données de concept au cas d''utilisation clinique auquel il correspond le mieux."},"leftItems":[{"id":"1","text":{"en":"Numeric","fr":"Numérique"}},{"id":"2","text":{"en":"Coded","fr":"Codé"}},{"id":"3","text":{"en":"Text","fr":"Texte"}},{"id":"4","text":{"en":"Date","fr":"Date"}},{"id":"5","text":{"en":"Boolean","fr":"Booléen"}}],"rightItems":[{"id":"a","text":{"en":"Recording the date a patient was admitted to the hospital","fr":"Enregistrer la date d''admission d''un patient à l''hôpital"}},{"id":"b","text":{"en":"Selecting a patient''s blood type from a predefined list of options","fr":"Sélectionner le groupe sanguin d''un patient dans une liste d''options prédéfinies"}},{"id":"c","text":{"en":"Capturing a simple yes/no answer to whether the patient is currently a smoker","fr":"Capturer une réponse simple oui/non indiquant si le patient est actuellement fumeur"}},{"id":"d","text":{"en":"Documenting a patient''s chief complaint in their own words","fr":"Documenter la plainte principale du patient dans ses propres mots"}},{"id":"e","text":{"en":"Recording a patient''s temperature reading in degrees Celsius","fr":"Enregistrer la température d''un patient en degrés Celsius"}}]}', '{"correctMatches":{"1":"e","2":"b","3":"d","4":"a","5":"c"}}', '{"correct":{"en":"Excellent! You understand the five essential datatypes from the lesson. Numeric handles measurements with units, Coded captures answers from a predefined list, Text accepts free-form input, Date stores calendar values, and Boolean records simple yes/no responses. Choosing the right datatype is the first step in form design - it determines how data is stored, validated, and reported. Get this right and your forms produce clean, comparable data automatically.","fr":"Excellent ! Vous comprenez les cinq types de données essentiels de la leçon. Numérique gère les mesures avec unités, Codé capture les réponses d''une liste prédéfinie, Texte accepte la saisie libre, Date stocke les valeurs de calendrier, et Booléen enregistre les réponses simples oui/non. Choisir le bon type de données est la première étape dans la conception de formulaire - il détermine comment les données sont stockées, validées et rapportées. Faites le bon choix et vos formulaires produisent automatiquement des données propres et comparables."},"incorrect":{"en":"Review the Essential Field Types section in Lesson 3. Each datatype has a distinct purpose: Numeric for measurements, Coded for answers from a fixed list, Text for free-form description, Date for calendar values, and Boolean for yes/no questions. Match each scenario by asking: what kind of value am I storing?","fr":"Révisez la section Types de champs essentiels dans la Leçon 3. Chaque type de données a un objectif distinct : Numérique pour les mesures, Codé pour les réponses d''une liste fixe, Texte pour la description libre, Date pour les valeurs de calendrier, et Booléen pour les questions oui/non. Associez chaque scénario en vous demandant : quel type de valeur est-ce que je stocke ?"}}', TRUE, 1, NOW(), FALSE);
SET @exercise_id_3 = LAST_INSERT_ID();


-- ===================================================================
-- EXERCISE 4: Create Vital Signs Form (FORM_CREATION)
-- ===================================================================
VALUES (UUID(), 'FORM_CREATION', '{"instructions":{"en":"Create a complete Vital Signs form according to the specifications below. This comprehensive exercise demonstrates the entire form creation workflow including structure, concept linking, field types, and validation.","fr":"Créez un formulaire complet de Signes vitaux selon les spécifications ci-dessous. Cet exercice complet démontre l''ensemble du flux de création de formulaire, y compris la structure, la liaison de concepts, les types de champs et la validation."},"requirements":{"name":{"en":"Vital Signs Form","fr":"Formulaire de signes vitaux"},"description":{"en":"A comprehensive form for recording vital sign measurements during patient encounters","fr":"Un formulaire complet pour enregistrer les mesures de signes vitaux lors des rencontres avec les patients"},"version":"1.0","encounterType":"Vitals","published":false,"pages":[{"label":{"en":"Vital Signs","fr":"Signes vitaux"},"sections":[{"label":{"en":"Basic Measurements","fr":"Mesures de base"},"isExpanded":true,"questions":[{"id":{"en":"weight","fr":"poids"},"label":{"en":"Weight (kg)","fr":"Poids (kg)"},"required":true,"type":"obs","questionOptions":{"rendering":"number","concept":{"id":"5089AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA","name":{"en":"Weight (kg)","fr":"Poids (kg)"}},"min":"0","max":"500"}},{"id":{"en":"height","fr":"taille"},"label":{"en":"Height (cm)","fr":"Taille (cm)"},"required":true,"type":"obs","questionOptions":{"rendering":"number","concept":{"id":"5090AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA","name":{"en":"Height (cm)","fr":"Taille (cm)"}},"min":"0","max":"300"}},{"id":{"en":"temperature","fr":"température"},"label":{"en":"Temperature (°C)","fr":"Température (°C)"},"required":true,"type":"obs","questionOptions":{"rendering":"number","concept":{"id":"5088AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA","name":{"en":"Temperature (c)","fr":"Température (c)"}},"min":"30","max":"45"}}]}]}]}}', '{}', '{"correct":{"en":"Excellent! You have successfully created a complete, well-structured vital signs form. Your form demonstrates understanding of: (1) The three-level hierarchy with one page containing one section with multiple questions, (2) Proper concept linking for each measurement to standardized concepts, (3) Appropriate field types (numeric rendering for all measurements), (4) Essential validation (required fields and min/max ranges), and (5) User-friendly organization with clear labels. This form is ready for testing in a development environment. Forms like this are fundamental to clinical operations - vital signs are collected at almost every patient visit, so a well-designed vital signs form directly improves care quality and efficiency.","fr":"Excellent ! Vous avez créé avec succès un formulaire de signes vitaux complet et bien structuré. Votre formulaire démontre la compréhension de : (1) La hiérarchie à trois niveaux avec une page contenant une section avec plusieurs questions, (2) La liaison appropriée de concepts pour chaque mesure à des concepts standardisés, (3) Les types de champs appropriés (rendu numérique pour toutes les mesures), (4) La validation essentielle (champs requis et plages min/max), et (5) L''organisation conviviale avec des étiquettes claires. Ce formulaire est prêt pour les tests dans un environnement de développement. Les formulaires comme celui-ci sont fondamentaux pour les opérations cliniques - les signes vitaux sont collectés à presque chaque visite de patient, donc un formulaire de signes vitaux bien conçu améliore directement la qualité et l''efficacité des soins."}}', TRUE, 1, NOW(), FALSE);
SET @exercise_id_4 = LAST_INSERT_ID();


